// src/utils/helpers.js
export const statusBadgeClass = (s) => {
  if (s === "Done")        return "badge-done";
  if (s === "In Progress") return "badge-inprogress";
  if (s === "Hold")        return "badge-hold";
  return "badge-todo";
};
export const statusSelectClass = (s) => {
  if (s === "Done")        return "status-done";
  if (s === "In Progress") return "status-inprogress";
  if (s === "Hold")        return "status-hold";
  return "status-todo";
};
export const statusDotColor = (s) => {
  if (s === "Done")        return "#16a34a";
  if (s === "In Progress") return "#1d4ed8";
  if (s === "Hold")        return "#d97706";
  return "#6b7280";
};
export const formatMinutes = (m) => {
  const mins = parseInt(m) || 0;
  const h = Math.floor(mins / 60), r = mins % 60;
  if (h === 0 && r === 0) return `0h`;
  if (h === 0) return `${r}m`;
  if (r === 0) return `${h}h`;
  return `${h}h ${r}m`;
};
export const todayISO = () => new Date().toISOString().split("T")[0];
export const computeStats = (tasks = []) => {
  const done       = tasks.filter(t => t.status === "Done").length;
  const inProgress = tasks.filter(t => t.status === "In Progress").length;
  const hold       = tasks.filter(t => t.status === "Hold").length;
  const todo       = tasks.filter(t => t.status === "To Do").length;
  const totalMins  = tasks.reduce((s, t) => s + (parseInt(t.totalMinutes) || 0), 0);
  const total      = tasks.length;
  const pct        = total ? Math.round((done / total) * 100) : 0;
  return { total, done, inProgress, hold, todo, totalMins, pct };
};

export const getWeekKey = (date = new Date()) => {
  const d    = new Date(date);
  const jan1 = new Date(d.getFullYear(), 0, 1);
  const week = Math.ceil(((d - jan1) / 86400000 + jan1.getDay() + 1) / 7);
  return `${d.getFullYear()}-W${String(week).padStart(2, "0")}`;
};

export const weeklyMinsFromTasks = (tasks) => {
  const wk = getWeekKey();
  return tasks
    .filter(t => {
      if (!t.date) return false;
      const d    = new Date(t.date);
      const jan1 = new Date(d.getFullYear(), 0, 1);
      const week = Math.ceil(((d - jan1) / 86400000 + jan1.getDay() + 1) / 7);
      return `${d.getFullYear()}-W${String(week).padStart(2, "0")}` === wk;
    })
    .reduce((s, t) => s + (parseInt(t.totalMinutes) || 0), 0);
};
